 98	async function fetchRemoteJwks(
 99	  fetchImplementation: typeof fetch,
100	  url: Parameters<FetchImplementation>[0],
101	  options: Parameters<FetchImplementation>[1],
102	): Promise<Response> {
103	  let response: Response;
104	
105	  try {
106	    response = await fetchImplementation(url, options);
107	  } catch (error) {
108	    throw new OidcProviderJwksError(
109	      hasErrorName(error, "TimeoutError") ? "ERR_OIDC_JWKS_TIMEOUT" : "ERR_OIDC_JWKS_FETCH_FAILED",
110	      { cause: error },
111	    );
112	  }
113	
114	  if (response.status !== 200) {
115	    throw new OidcProviderJwksError("ERR_OIDC_JWKS_HTTP_STATUS", {
116	      providerStatus: response.status,
117	    });
118	  }
119	
120	  let jwks: unknown;
121	
122	  try {
123	    jwks = await response.clone().json();
124	  } catch (error) {
125	    throw new OidcProviderJwksError("ERR_OIDC_JWKS_JSON_PARSE_FAILED", { cause: error });
126	  }
127	
128	  if (!isJsonWebKeySetShape(jwks)) {
129	    throw new OidcProviderJwksError("ERR_OIDC_JWKS_INVALID");
130	  }
131	
132	  const headers = new Headers(response.headers);
133	  headers.set("content-type", "application/json");
134	
135	  return new Response(response.body, {
136	    headers,
137	    status: response.status,
138	    statusText: response.statusText,
139	  });
140	}
